/**
 * Layer 8: Advanced Cryptography
 * Shamir Secret Sharing and Time-lock Puzzles
 */

import { sha256 } from '@noble/hashes/sha2';
import { randomBytes } from '@noble/hashes/utils';

/**
 * ShamirSecretSharing - Implementación de Shamir's Secret Sharing
 * Divide un secreto en N partes, requiere K partes para reconstruir
 */
export class ShamirSecretSharing {
  private readonly prime: bigint;
  private readonly primeHex: string;

  constructor() {
    // Usar un primo seguro de 256 bits
    this.prime = BigInt('');
    this.primeHex = this.prime.toString(16);
  }

  /**
   * Dividir secreto en shares
   * @param secret El secreto a dividir
   * @param numShares Número de shares a generar
   * @param threshold Número mínimo de shares para reconstruir
   */
  async split(secret: string, numShares: number, threshold: number): Promise<string[]> {
    if (threshold > numShares) {
      throw new Error('Threshold must be less than or equal to number of shares');
    }

    const secretBigInt = this.stringToBigInt(secret);
    const shares: bigint[] = [];

    // Generar coeficientes aleatorios para el polinomio
    const coefficients: bigint[] = [secretBigInt];
    for (let i = 1; i < threshold; i++) {
      coefficients.push(this.randomBigInt(this.prime));
    }

    // Evaluar polinomio en diferentes puntos
    for (let x = 1; x <= numShares; x++) {
      let y = coefficients[0];
      for (let i = 1; i < coefficients.length; i++) {
        y = (y + coefficients[i] * BigInt(x) ** BigInt(i)) % this.prime;
      }
      shares.push(y);
    }

    // Retornar como strings hex
    return shares.map((share, i) => {
      const x = (i + 1).toString(16).padStart(2, '0');
      const y = share.toString(16).padStart(64, '0');
      return x + y;
    });
  }

  /**
   * Reconstruir secreto desde shares
   * @param shares Array de shares
   */
  async reconstruct(shares: string[]): Promise<string> {
    if (shares.length < 2) {
      throw new Error('Need at least 2 shares to reconstruct');
    }

    // Parsear shares
    const points: [bigint, bigint][] = shares.map(share => {
      const x = BigInt('0x' + share.slice(0, 2));
      const y = BigInt('0x' + share.slice(2));
      return [x, y];
    });

    // Interpolación de Lagrange
    let secret = BigInt(0);
    for (let i = 0; i < points.length; i++) {
      let numerator = BigInt(1);
      let denominator = BigInt(1);

      for (let j = 0; j < points.length; j++) {
        if (i !== j) {
          numerator = (numerator * BigInt(-points[j][0])) % this.prime;
          denominator = (denominator * (points[i][0] - points[j][0])) % this.prime;
        }
      }

      const lagrange = numerator * this.modInverse(denominator, this.prime) % this.prime;
      secret = (secret + points[i][1] * lagrange) % this.prime;
    }

    if (secret < 0) {
      secret = (secret + this.prime) % this.prime;
    }

    return this.bigIntToString(secret);
  }

  private stringToBigInt(str: string): bigint {
    const bytes = new TextEncoder().encode(str);
    let result = BigInt(0);
    for (const byte of bytes) {
      result = (result << BigInt(8)) + BigInt(byte);
    }
    return result;
  }

  private bigIntToString(bigInt: bigint): string {
    let result = '';
    let temp = bigInt;
    while (temp > 0) {
      const byte = Number(temp & BigInt(255));
      result = String.fromCharCode(byte) + result;
      temp = temp >> BigInt(8);
    }
    return result;
  }

  private randomBigInt(mod: bigint): bigint {
    const bytes = randomBytes(32);
    let result = BigInt(0);
    for (const byte of bytes) {
      result = (result << BigInt(8)) + BigInt(byte);
    }
    return result % mod;
  }

  private modInverse(a: bigint, m: bigint): bigint {
    let [old_r, r] = [a, m];
    let [old_s, s] = [BigInt(1), BigInt(0)];

    while (r !== BigInt(0)) {
      const quotient = old_r / r;
      [old_r, r] = [r, old_r - quotient * r];
      [old_s, s] = [s, old_s - quotient * s];
    }

    if (old_s < 0) {
      return old_s + m;
    }
    return old_s;
  }
}

/**
 * TimeLockPuzzle - Puzzle de bloqueo temporal
 * Permite encriptar datos que solo pueden ser desencriptados después de un tiempo
 */
export class TimeLockPuzzle {
  /**
   * Crear un puzzle de tiempo
   * @param secret El secreto a bloquear
   * @param delayMs Tiempo de espera en milisegundos
   */
  async create(secret: string, delayMs: number): Promise<TimeLockData> {
    const startTime = Date.now();
    const iterations = Math.floor(delayMs / 100); // ~100ms por iteración
    
    // Generar seed aleatorio
    const seed = randomBytes(32);
    
    // Calcular hash iterativo (POW simple)
    let hash = sha256(seed);
    for (let i = 0; i < iterations; i++) {
      hash = sha256(hash);
    }
    
    // Encriptar secreto con el hash final
    const key = new Uint8Array(hash);
    const encrypted = await this.encrypt(secret, key);
    
    return {
      encrypted,
      seed: Array.from(seed),
      iterations,
      startTime,
    };
  }

  /**
   * Resolver puzzle (requiere tiempo)
   * @param puzzle Datos del puzzle
   */
  async solve(puzzle: TimeLockData): Promise<string> {
    const seed = new Uint8Array(puzzle.seed);
    let hash = sha256(seed);
    
    // Recalcular hashes
    for (let i = 0; i < puzzle.iterations; i++) {
      hash = sha256(hash);
    }
    
    // Desencriptar
    const key = new Uint8Array(hash);
    return this.decrypt(puzzle.encrypted, key);
  }

  /**
   * Verificar si el puzzle está listo para resolver
   */
  isReady(puzzle: TimeLockData): boolean {
    const elapsed = Date.now() - puzzle.startTime;
    const requiredTime = puzzle.iterations * 100;
    return elapsed >= requiredTime;
  }

  /**
   * Obtener tiempo restante
   */
  getRemainingTime(puzzle: TimeLockData): number {
    const elapsed = Date.now() - puzzle.startTime;
    const requiredTime = puzzle.iterations * 100;
    return Math.max(0, requiredTime - elapsed);
  }

  private async encrypt(data: string, key: Uint8Array): Promise<string> {
    const encoded = new TextEncoder().encode(data);
    const encrypted: number[] = [];
    
    for (let i = 0; i < encoded.length; i++) {
      encrypted.push(encoded[i] ^ key[i % key.length]);
    }
    
    return btoa(String.fromCharCode(...encrypted));
  }

  private async decrypt(data: string, key: Uint8Array): Promise<string> {
    const encrypted = Uint8Array.from(atob(data), c => c.charCodeAt(0));
    const decrypted: number[] = [];
    
    for (let i = 0; i < encrypted.length; i++) {
      decrypted.push(encrypted[i] ^ key[i % key.length]);
    }
    
    return new TextDecoder().decode(Uint8Array.from(decrypted));
  }
}

export interface TimeLockData {
  encrypted: string;
  seed: number[];
  iterations: number;
  startTime: number;
}
